    targetTicket.source_mode = replacementSourceMode ?? undefined

    if (!replacementSourceTicket.follow_up_ticket_ids.includes(targetTicket.id)) {
      replacementSourceTicket.follow_up_ticket_ids.push(targetTicket.id)
