347	      current += char
348	      escaped = false
349	      continue
350	    }
351	    if (char === "\\") {
352	      escaped = true
353	      continue
354	    }
355	    if (quote) {
356	      if (char === quote) {
357	        quote = null
358	      } else {
359	        current += char
360	      }
361	      continue
362	    }
363	    if (char === '"' || char === "'") {
364	      quote = char
365	      continue
366	    }
367	    if (/\s/.test(char)) {
368	      if (current) {
369	        tokens.push(current)
370	        current = ""
371	      }
372	      continue
373	    }
374	    current += char
