   281	
   282	  return commands
   283	}
   284	
   285	async function detectAcceptanceCommands(root: string, ticket: { acceptance?: unknown }): Promise<CommandSpec[]> {
   286	  const acceptanceCommands = inferAcceptanceSmokeCommands(ticket)
   287	  if (acceptanceCommands.length === 0) {
   288	    return []
   289	  }
   290	  const seen = new Set<string>()
   291	  return acceptanceCommands.filter((command) => {
   292	    const key = renderCommand(command)
   293	    if (seen.has(key)) {
   294	      return false
   295	    }
   296	    seen.add(key)
   297	    return true
   298	  })
   299	}
   300	
   301	async function detectRustCommands(root: string): Promise<CommandSpec[]> {
   302	  if (!(await exists(join(root, "Cargo.toml")))) {
   303	    return []
   304	  }
   305	
   306	  return [
   307	    { label: "cargo check", argv: ["cargo", "check"], reason: "Rust compile smoke check" },
   308	    { label: "cargo test", argv: ["cargo", "test"], reason: "Rust test suite" },
   309	  ]
   310	}
   311	
   312	async function detectGoCommands(root: string): Promise<CommandSpec[]> {
   313	  if (!(await exists(join(root, "go.mod")))) {
   314	    return []
   315	  }
   316	
   317	  return [{ label: "go test ./...", argv: ["go", "test", "./..."], reason: "Go test suite" }]
   318	}
   319	
   320	async function detectMakeSmokeTarget(root: string): Promise<CommandSpec[]> {
   321	  for (const fileName of ["Makefile", "makefile", "GNUmakefile"]) {
   322	    const path = join(root, fileName)
   323	    if (!(await exists(path))) continue
   324	    const content = await readFile(path, "utf-8").catch(() => "")
   325	    if (/^smoke-test\s*:/m.test(content)) {
   326	      return [{ label: "make smoke-test", argv: ["make", "smoke-test"], reason: `${fileName} override target` }]
   327	    }
   328	    if (/^smoke_test\s*:/m.test(content)) {
   329	      return [{ label: "make smoke_test", argv: ["make", "smoke_test"], reason: `${fileName} override target` }]
   330	    }
   331	  }
   332	  return []
   333	}
   334	
   335	function looksLikeShellStyleOverride(command: string): boolean {
   336	  return /\s|["'`;&|]/.test(command.trim())
   337	}
   338	
   339	function tokenizeCommandString(command: string): string[] {
   340	  const tokens: string[] = []
   341	  let current = ""
   342	  let quote: '"' | "'" | null = null
   343	  let escaped = false
   344	
   345	  for (const char of command) {
   346	    if (escaped) {
   347	      current += char
   348	      escaped = false
   349	      continue
   350	    }
   351	    if (char === "\\") {
   352	      escaped = true
   353	      continue
   354	    }
   355	    if (quote) {
   356	      if (char === quote) {
   357	        quote = null
   358	      } else {
   359	        current += char
   360	      }
   361	      continue
   362	    }
   363	    if (char === '"' || char === "'") {
   364	      quote = char
   365	      continue
   366	    }
   367	    if (/\s/.test(char)) {
   368	      if (current) {
   369	        tokens.push(current)
   370	        current = ""
   371	      }
   372	      continue
   373	    }
   374	    current += char
   375	  }
   376	
   377	  if (escaped) {
   378	    current += "\\"
   379	  }
   380	  if (quote) {
   381	    throw new Error("command_override contains an unmatched quote.")
   382	  }
   383	  if (current) {
   384	    tokens.push(current)
   385	  }
   386	  return tokens
   387	}
   388	
   389	function parseOverrideTokens(tokens: string[], label: string): CommandSpec {
   390	  const env_overrides: Record<string, string> = {}
   391	
   392	  while (tokens.length > 0 && ENV_ASSIGNMENT_PATTERN.test(tokens[0] ?? "")) {
   393	    const assignment = tokens.shift() ?? ""
   394	    const separator = assignment.indexOf("=")
   395	    if (separator <= 0) {
   396	      break
   397	    }
   398	    env_overrides[assignment.slice(0, separator)] = assignment.slice(separator + 1)
   399	  }
   400	
   401	  if (tokens.length === 0) {
   402	    throw new Error("command_override must include an executable after any leading KEY=VALUE environment assignments.")
   403	  }
   404	
   405	  return {
   406	    label,
   407	    argv: tokens,
   408	    reason: "Explicit smoke-test command override supplied by the caller.",
   409	    env_overrides: Object.keys(env_overrides).length > 0 ? env_overrides : undefined,
   410	  }
   411	}
   412	
   413	function parseCommandOverride(rawOverride: string[]): CommandSpec[] {
   414	  if (rawOverride.length === 0) {
   415	    return []
   416	  }
   417	  if (rawOverride.length === 1) {
   418	    return [parseOverrideTokens(tokenizeCommandString(rawOverride[0] ?? ""), "command override 1")]
   419	  }
   420	
   421	  const shellStyleEntries = rawOverride.filter((item) => looksLikeShellStyleOverride(item))
   422	  if (shellStyleEntries.length === 0) {
   423	    return [parseOverrideTokens([...rawOverride], "command override 1")]
   424	  }
   425	  if (shellStyleEntries.length !== rawOverride.length) {
   426	    throw new Error("command_override cannot mix tokenized argv entries with multiple shell-style command strings.")
   427	  }
   428	
   429	  return rawOverride.map((command, index) => parseOverrideTokens(tokenizeCommandString(command), `command override ${index + 1}`))
   430	}
   431	
   432	async function detectCommands(root: string, ticket: { acceptance?: unknown }, args: SmokeArgs): Promise<CommandSpec[]> {
   433	  if (Array.isArray(args.command_override) && args.command_override.length > 0) {
   434	    return parseCommandOverride(args.command_override)
   435	  }
   436	  const acceptanceCommands = await detectAcceptanceCommands(root, ticket)
   437	  if (acceptanceCommands.length > 0) {
   438	    return acceptanceCommands
   439	  }
   440	  const makeOverride = await detectMakeSmokeTarget(root)
   441	  if (makeOverride.length > 0) {
   442	    return makeOverride
   443	  }
   444	
   445	  const commands = [
   446	    ...(await detectNodeCommands(root)),
   447	    ...(await detectPythonCommands(root, args)),
   448	    ...(await detectRustCommands(root)),
   449	    ...(await detectGoCommands(root)),
   450	  ]
   451	
   452	  const seen = new Set<string>()
   453	  return commands.filter((command) => {
   454	    const key = renderCommand(command)
   455	    if (seen.has(key)) {
   456	      return false
   457	    }
   458	    seen.add(key)
   459	    return true
   460	  })

