  1	import { tool } from "@opencode-ai/plugin"
  2	import {
  3	  createTicketRecord,
  4	  getTicket,
  5	  loadManifest,
  6	  loadWorkflowState,
  7	  saveWorkflowBundle,
  8	  setPlanApprovedForTicket,
  9	  syncWorkflowSelection,
 10	  ticketFilePath,
 11	  type TicketSourceMode,
 12	} from "../lib/workflow"
 13	
 14	function normalizeOptional(value: string | undefined): string | undefined {
 15	  if (typeof value !== "string") return undefined
 16	  const normalized = value.trim()
 17	  return normalized || undefined
 18	}
 19	
 20	export default tool({
 21	  description: "Create a new ticket or linked follow-up ticket, including process-verification, post-completion issue, and open-parent split follow-up tickets.",
 22	  args: {
 23	    id: tool.schema.string().describe("New ticket id."),
 24	    title: tool.schema.string().describe("New ticket title."),
 25	    lane: tool.schema.string().describe("Owning lane or project area."),
 26	    wave: tool.schema.number().int().describe("Execution wave number."),
 27	    summary: tool.schema.string().describe("Ticket summary."),
 28	    acceptance: tool.schema.array(tool.schema.string()).describe("Acceptance criteria list."),
 29	    depends_on: tool.schema.array(tool.schema.string()).describe("Dependency ticket ids.").optional(),
 30	    decision_blockers: tool.schema.array(tool.schema.string()).describe("Unresolved blockers for this ticket.").optional(),
 31	    parallel_safe: tool.schema.boolean().describe("Whether the ticket can be advanced in a parallel lane when dependencies are satisfied.").optional(),
 32	    overlap_risk: tool.schema.enum(["low", "medium", "high"]).describe("Expected overlap risk with other tickets.").optional(),
 33	    source_ticket_id: tool.schema.string().describe("Optional source ticket that this ticket extends or remediates.").optional(),
 34	    source_mode: tool.schema.enum(["process_verification", "post_completion_issue", "net_new_scope", "split_scope"]).describe("Why this ticket is being created.").optional(),
 35	    evidence_artifact_path: tool.schema.string().describe("Optional registered artifact path that justifies creation of this linked ticket.").optional(),
 36	    activate: tool.schema.boolean().describe("Whether to make the new ticket active immediately.").optional(),
 37	  },
 38	  async execute(args) {
 39	    const manifest = await loadManifest()
 40	    const workflow = await loadWorkflowState()
 41	    const sourceMode: TicketSourceMode = args.source_mode || "net_new_scope"
 42	    const sourceTicketId = normalizeOptional(args.source_ticket_id)
 43	    const evidenceArtifactPath = normalizeOptional(args.evidence_artifact_path)
 44	
 45	    if (manifest.tickets.some((ticket) => ticket.id === args.id.trim())) {
 46	      throw new Error(`Ticket already exists: ${args.id.trim()}`)
 47	    }
 48	
 49	    const ticket = createTicketRecord({
 50	      id: args.id,
 51	      title: args.title,
 52	      lane: args.lane,
 53	      wave: args.wave,
 54	      summary: args.summary,
 55	      acceptance: args.acceptance,
 56	      depends_on: args.depends_on,
 57	      decision_blockers: args.decision_blockers,
 58	      parallel_safe: args.parallel_safe,
 59	      overlap_risk: args.overlap_risk,
 60	      source_ticket_id: sourceTicketId,
 61	      source_mode: sourceMode,
 62	    })
 63	
 64	    for (const dependency of ticket.depends_on) {
 65	      getTicket(manifest, dependency)
 66	    }
 67	
 68	    let sourceTicket = undefined as ReturnType<typeof getTicket> | undefined
 69	    if (sourceMode !== "net_new_scope") {
 70	      if (!sourceTicketId) {
 71	        throw new Error(`source_ticket_id is required when source_mode is ${sourceMode}.`)
 72	      }
 73	      sourceTicket = getTicket(manifest, sourceTicketId)
 74	
 75	      if (ticket.depends_on.includes(sourceTicket.id)) {
 76	        throw new Error(`Ticket ${ticket.id} cannot depend on its source ticket ${sourceTicket.id}; reconcile lineage or split scope instead of creating a contradictory dependency.`)
 77	      }
 78	
 79	      if (sourceMode === "process_verification") {
 80	        if (!workflow.pending_process_verification) {
 81	          throw new Error("process_verification ticket creation is only available while pending_process_verification is true.")
 82	        }
 83	        if (sourceTicket.status !== "done") {
 84	          throw new Error(`Source ticket ${sourceTicket.id} must be done before creating a process-verification follow-up ticket.`)
 85	        }
 86	        if (!evidenceArtifactPath) {
 87	          throw new Error("evidence_artifact_path is required for process_verification ticket creation.")
 88	        }
 89	        const verificationArtifact = sourceTicket.artifacts.find(
 90	          (artifact) =>
 91	            artifact.path === evidenceArtifactPath &&
 92	            artifact.stage === "review" &&
 93	            artifact.kind === "backlog-verification" &&
 94	            artifact.trust_state === "current",
 95	        )
 96	        if (!verificationArtifact) {
 97	          throw new Error(
 98	            `Source ticket ${sourceTicket.id} does not have a current review/backlog-verification artifact at ${evidenceArtifactPath}.`,
 99	          )
100	        }
101	      }
102	
103	      if (sourceMode === "post_completion_issue") {
104	        if (sourceTicket.status !== "done" && !["done", "superseded"].includes(sourceTicket.resolution_state)) {
105	          throw new Error(`Source ticket ${sourceTicket.id} must already represent completed historical scope before creating a post-completion issue ticket.`)
106	        }
107	        if (!evidenceArtifactPath) {
108	          throw new Error("evidence_artifact_path is required for post_completion_issue ticket creation.")
109	        }
110	        const evidenceArtifact = sourceTicket.artifacts.find((artifact) => artifact.path === evidenceArtifactPath)
111	        if (!evidenceArtifact) {
112	          throw new Error(`Source ticket ${sourceTicket.id} does not reference the evidence artifact ${evidenceArtifactPath}.`)
113	        }
114	      }
115	
116	      if (sourceMode === "split_scope") {
117	        if (!["open", "reopened"].includes(sourceTicket.resolution_state) || sourceTicket.status === "done") {
118	          throw new Error(`Source ticket ${sourceTicket.id} must remain open or reopened before creating a split-scope child ticket.`)
119	        }
120	      }
121	    }
122	
123	    manifest.tickets.push(ticket)
124	    if (sourceTicket && !sourceTicket.follow_up_ticket_ids.includes(ticket.id)) {
125	      sourceTicket.follow_up_ticket_ids.push(ticket.id)
126	    }
127	    if (sourceTicket && sourceMode === "split_scope") {
128	      const splitNote = `Split scope delegated to follow-up ticket ${ticket.id}. Keep the parent open and non-foreground until the child work lands.`
129	      if (!sourceTicket.decision_blockers.includes(splitNote)) {
130	        sourceTicket.decision_blockers.push(splitNote)
131	      }
132	    }
133	
134	    setPlanApprovedForTicket(workflow, ticket.id, false)
135	    const activateNewTicket = typeof args.activate === "boolean"
136	      ? args.activate
137	      : sourceMode === "split_scope" && sourceTicket?.id === manifest.active_ticket
138	    if (activateNewTicket) {
139	      manifest.active_ticket = ticket.id
140	    }
141	    syncWorkflowSelection(workflow, manifest)
142	
143	    await saveWorkflowBundle({ workflow, manifest })
144	
145	    return JSON.stringify(
146	      {
147	        created_ticket: ticket.id,
148	        path: ticketFilePath(ticket.id),
149	        status: ticket.status,
150	        source_ticket_id: sourceTicket?.id || null,
151	        source_mode: sourceMode,
152	        evidence_artifact_path: evidenceArtifactPath || null,
153	        activated: activateNewTicket,
154	      },
155	      null,
156	      2,
157	    )
158	  },
159	})

